import Blog from '../components/Blog';
import Movie from '../components/Movie';
import { useState } from 'react';


const Home = () => {
    const [home, setHome] = useState(true);
    const [blog, setBlog] = useState(false);
    const [about, setAbout] = useState(false);
    const [movie, setMovie] = useState(false);
    const onClickBlog = () => {
        setHome(false);
        setBlog(true);
        setAbout(false);
        setMovie(false);
    }
    const onClickHome = () => {
        setHome(true);
        setBlog(false);
        setAbout(false);
        setMovie(false);
    }
    const onClickAbout = () => {
        setHome(false);
        setBlog(false);
        setAbout(true);
        setMovie(false);
    }
    const onClickMovie = () => {
        setHome(false);
        setBlog(false);
        setAbout(false);
        setMovie(true);
    }
    return (
        <div className="App">

            <nav>
                <ul>
                    <li onClick={onClickHome}>Home</li>
                    <li onClick={onClickBlog}>Blog</li>
                    <li onClick={onClickAbout}>About</li>
                    <li onClick={onClickMovie}>Movie</li>
                </ul>
            </nav>
            <section>
                {home ? <h1>Welcome to My Home!</h1> : null}
                {blog ? <Blog /> : null}
                {about ? <h1>About Me..</h1> : null}
                {movie ? <Movie /> : null}
            </section>
        </div>
    );
}

export default Home;